from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.backends import default_backend
from cryptography.hazmat.primitives import padding
import os
import base64

def encrypt_credit_card(credit_card_number, key):
    # Generate a random salt
    salt = os.urandom(16)
    
    # Derive a key using PBKDF2HMAC
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=100000,
        backend=default_backend()
    )
    derived_key = kdf.derive(key)
    
    # Generate a random IV
    iv = os.urandom(16)
    
    # Create a Cipher object
    cipher = Cipher(algorithms.AES(derived_key), modes.CBC(iv), backend=default_backend())
    encryptor = cipher.encryptor()
    
    # Pad the credit card number
    padder = padding.PKCS7(algorithms.AES.block_size).padder()
    padded_data = padder.update(credit_card_number.encode()) + padder.finalize()
    
    # Encrypt the padded credit card number
    encrypted = encryptor.update(padded_data) + encryptor.finalize()
    
    # Return the salt, iv, and encrypted data, all base64 encoded
    return base64.b64encode(salt + iv + encrypted).decode()

def decrypt_credit_card(encrypted_data, key):
    # Decode the base64 encoded data
    encrypted_data = base64.b64decode(encrypted_data)
    
    # Extract the salt, iv, and encrypted data
    salt = encrypted_data[:16]
    iv = encrypted_data[16:32]
    encrypted = encrypted_data[32:]
    
    # Derive the key using the same salt
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=100000,
        backend=default_backend()
    )
    derived_key = kdf.derive(key)
    
    # Create a Cipher object
    cipher = Cipher(algorithms.AES(derived_key), modes.CBC(iv), backend=default_backend())
    decryptor = cipher.decryptor()
    
    # Decrypt the data
    decrypted_padded = decryptor.update(encrypted) + decryptor.finalize()
    
    # Unpad the decrypted data
    unpadder = padding.PKCS7(algorithms.AES.block_size).unpadder()
    decrypted = unpadder.update(decrypted_padded) + unpadder.finalize()
    
    return decrypted.decode()

